const fs = require('fs');
const path = require('path');

export async function execute(skillId: string, description: string, code: string) {
  const SKILLS_DIR = path.resolve(__dirname, '../skills');
  if (!fs.existsSync(SKILLS_DIR)) {
    fs.mkdirSync(SKILLS_DIR, { recursive: true });
  }

  const safeId = skillId.toLowerCase().replace(/[^a-z0-9-]+/g, '-');
  const filePath = path.join(SKILLS_DIR, `${safeId}.json`);

  const newSkill = {
    id: safeId,
    name: skillId,
    description: description,
    code: code,
    readme: `# ${skillId}\nAutomatically generated skill. ${description}`,
    dependencies: []
  };

  try {
    fs.writeFileSync(filePath, JSON.stringify(newSkill, null, 2), 'utf8');
    return { success: true, message: `Successfully created and hot-loaded new skill: ${safeId}. You can now use it.` };
  } catch (err: any) {
    return { success: false, error: err.message };
  }
}
